using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API at the given path and returns the JSON response.")]
    public static async Task<string> FetchApiData(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiTools> logger,
        [Description("The API endpoint path to call (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("FetchApiData called with path: {Path}", path);

        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        var result = JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });

        logger.LogInformation("FetchApiData succeeded for path: {Path}", path);
        return result;
    }
}

