using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerPromptType]
public sealed class SummarizePrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks for a concise summary of the provided text.")]
    public static IEnumerable<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint (e.g. \"2 sentences\").")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in {maxLength}:"
            : "Summarize the following text concisely:";

        yield return new PromptMessage
        {
            Role = Role.User,
            Content = new Content
            {
                Type = "text",
                Text = $"{instruction}\n\n{text}"
            }
        };
    }
}

